def corrective_rag(query: str, max_retries: int = 2) -> str:
    for attempt in range(max_retries + 1):
        chunks = retriever.retrieve(query, top_k=10)
        relevant = [c for c in chunks if grader.grade(query, c).relevant]
        if len(relevant) >= 3:
            return synthesizer.generate(query, relevant)
        if attempt < max_retries:
            query = rewriter.rewrite(query, chunks)
    # Fallback: web search
    web_results = web_search(query)
    return synthesizer.generate(query, web_results)

def adaptive_rag(query: str) -> str:
    complexity = classify_complexity(query)  # "simple" | "moderate" | "complex"
    if complexity == "simple":
        return llm.invoke(query)
    elif complexity == "moderate":
        docs = retriever.retrieve(query, k=3)
        return generate_from_docs(query, docs)
    else:
        return multi_hop_retrieve_and_generate(query, max_hops=5)

from pydantic import BaseModel, Field from typing import Literal
class RouteQuery(BaseModel): datasource: Literal["vectorstore", "web_search", "direct_response", "api"] reasoning: str = Field(description="Why this route was chosen") confidence: float = Field(ge=0, le=1)
router_llm = ChatOpenAI(model="gpt-4o-mini").with_structured_output(RouteQuery)
